		"viz_gVVmqw63": {
			"type": "splunk.markdown",
			"options": {
				"markdown": "**Prefer ephemeral keys over static keys**\n\n\n**Use strong cryptography and security protocols over open, public networks.**"
			}
		},
		"viz_SnCAD1eF": {
			"type": "splunk.markdown",
			"options": {
				"markdown": "****Reporting and alerting on rogue, expired, or non-compliant certificates.****"
			}
		},
		"viz_F60EIVnw": {
			"type": "splunk.markdown",
			"options": {
				"markdown": "**SSL and early TLS no longer meet the security needs. Do not allow the use of SSL 2.0 or SSL 3.0.**"
			}
		},
		"viz_b3BRdJxs": {
			"type": "splunk.markdown",
			"options": {
				"markdown": "### **Develop and maintain secure systems and applications** \n\n**Look** **for,**\n\n- unauthorized applications\n\n- port spoofing\n\n- unauthorized Access**"
			}
		},
		"viz_oBqSjUIl": {
			"type": "splunk.markdown",
			"options": {
				"markdown": "### Insecure Protocol/Service/Port\nServices, protocols, or ports that transmit data or authentication credentials (for example, password/passphrase) in clear-text over the Internet\nxamples of insecure services, protocols, or ports include but are not limited to \n\n- FTP,\n\n - Telnet,\n\n - POP3,\n\n - IMAP,\n\n - SNMP v1 and v2\n\n - SMB v1 and v2."
			}
		},
		"viz_CXoYx6io": {
			"type": "splunk.markdown",
			"options": {
				"markdown": "**Track and monitor all access to network resources and cardholder data**\n\n"
			}
		},
		"viz_UaBXkMSx": {
			"type": "splunk.markdown",
			"options": {
				"markdown": "### **Encrypt transmission of cardholder data across open, public networks**"
			}
		}
	},
	"title": "PCI Compliance Dashboard",
	"description": "Dashboard helps organizations validate their PCI compliance posture",
	"inputs": {
		"input_global_trp": {
			"options": {
				"defaultValue": "-24h@h,now",
				"token": "global_time"
			},
			"title": "Global Time Range",
			"type": "input.timerange"
		}
	},
	"defaults": {
		"dataSources": {
			"ds.search": {
				"options": {
					"queryParameters": {
						"earliest": "$global_time.earliest$",
						"latest": "$global_time.latest$"
					}
				}
			},
			"ds.spl2": {
				"options": {
					"queryParameters": {
						"earliest": "$global_time.earliest$",
						"latest": "$global_time.latest$"
					}
				}
			}
		},
		"visualizations": {
			"global": {
				"showProgressBar": true
			}
		}
	},
	"dataSources": {
		"ds_2tJhbCFU": {
			"name": "Search_1 copy 1",
			"options": {
				"query": "| @spl2 FROM gigamon_dataset2\n| eval ssl_ext_sig_algorithm_sig = json_extract(_raw, \"ssl_ext_sig_algorithm_sig\")\n| stats count() AS log_count BY ssl_ext_sig_algorithm_sig\n| lookup Signature ssl_ext_sig_algorithm_sig OUTPUT Signature\n| where Signature != \"\"\n| eventstats sum(log_count) AS count BY Signature\n| dedup Signature\n| sort - count\n| table Signature, count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_CTKARhS9": {
			"name": "Search_1 copy 10",
			"options": {
				"query": "| @spl2\nFROM gigamon_dataset2\n| eval\n    app_name = json_extract(_raw, \"app_name\"),\n    src_ip = json_extract(_raw, \"src_ip\"),\n    dst_ip = json_extract(_raw, \"dst_ip\"),\n    src_port = json_extract(_raw, \"src_port\"),\n    dst_port = json_extract(_raw, \"dst_port\")\n| where app_name = \"ssh\"\n    AND dst_port != \"22\"\n    AND src_port != \"22\"\n| rename app_name AS App\n| table src_ip, dst_ip, src_port, dst_port, App",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_CTTGF2Gy": {
			"name": "Search_1 copy 6",
			"options": {
				"query": "| @spl2\nFROM gigamon_dataset2\n| eval\n    src_ip = json_extract(_raw, \"src_ip\"),\n    dst_ip = json_extract(_raw, \"dst_ip\"),\n    app_name = json_extract(_raw, \"app_name\"),\n    ssl_protocol_version = json_extract(_raw, \"ssl_protocol_version\")\n| lookup SSL_version ssl_protocol_version OUTPUT Version\n| where Version IN (\"SSLv3\", \"SSLv2\", \"TLS1.0\")\n| table Version, src_ip, dst_ip, app_name",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_E6pqpX3S": {
			"name": "Search_1 copy 12",
			"options": {
				"query": "| @spl2\nFROM gigamon_dataset2\n| eval\n    app_name = json_extract(_raw, \"app_name\"),\n    snmp_version = json_extract(_raw, \"snmp_version\")\n| where app_name = \"snmp\"\n    AND snmp_version IN (\"1\", \"2c\")\n| stats count() AS ccount BY snmp_version\n| rename snmp_version AS 'SNMP Version'\n| sort - ccount",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_EnaJchB2": {
			"name": "Search_1 copy 16",
			"options": {
				"query": "| @spl2\nFROM gigamon_dataset2\n| eval dst_mac = json_extract(_raw, \"dst_mac\")\n| stats count() AS ccount BY dst_mac\n| rename dst_mac AS 'Destination MAC'\n| sort - ccount\n| head 10",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_F6qVIIQv": {
			"name": "Search_1 copy 2",
			"options": {
				"query": "| @spl2 FROM gigamon_dataset2\n| eval\n    app_name_extracted = json_extract(_raw, \"app_name\"),\n    dst_ip_extracted = json_extract(_raw, \"dst_ip\"),\n    ssl_issuer_extracted = json_extract(_raw, \"ssl_issuer\"),\n    ssl_common_name_extracted = json_extract(_raw, \"ssl_common_name\"),\n    ssl_validity_not_after_extracted = json_extract(_raw, \"ssl_validity_not_after\")\n| eval ssl_validity_not_after_time = strptime(ssl_validity_not_after_extracted, \"%Y-%m-%d %H:%M:%S\")\n| WHERE ssl_validity_not_after_extracted != \"\"\n    AND ssl_common_name_extracted != \"\"\n    AND app_name_extracted != \"Unknown ssl\"\n    AND app_name_extracted != \"unknown\"\n    AND ssl_validity_not_after_time < now()\nGROUP BY\n    app_name_extracted,\n    dst_ip_extracted,\n    ssl_issuer_extracted,\n    ssl_common_name_extracted,\n    ssl_validity_not_after_extracted\nSELECT\n    count(*) AS count,\n    ssl_common_name_extracted AS 'Common Name',\n    ssl_issuer_extracted AS Issuer,\n    dst_ip_extracted AS 'Server IP',\n    app_name_extracted AS app_name,\n    ssl_validity_not_after_extracted AS 'Expiration Date'\nORDER BY \"Expiration Date\" DESC \n",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_LzI0I5Bm": {
			"name": "Search_1 copy 11",
			"options": {
				"query": "| @spl2\nFROM gigamon_dataset2\n| eval app_name = json_extract(_raw, \"app_name\")\n| where app_name IN (\"telnet\", \"ftp\", \"imap\", \"pop3\")\n| stats count() AS ccount BY app_name\n| rename app_name AS Application\n| sort - ccount\n| table Application, ccount",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_MBnXD5Nn": {
			"name": "Search_1 copy 8",
			"options": {
				"query": "| @spl2\nFROM gigamon_dataset2\n| eval app_name = json_extract(_raw, \"app_name\")\n| where (app_name = \"bittorrent\" OR app_name = \"utorrent\")\n    AND app_name != \"unknown\"\n| stats count() AS raw_count BY app_name\n| eval allnum = 1\n| rename app_name AS Application\n| stats sum(allnum) AS count BY Application",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_NCd4ieID": {
			"name": "Search_1 copy 5",
			"options": {
				"query": "| @spl2 FROM gigamon_dataset2\n| eval ssl_ext_sig_algorithm_hash = json_extract(_raw, \"ssl_ext_sig_algorithm_hash\")\n| stats count() AS count BY ssl_ext_sig_algorithm_hash\n| lookup Hash ssl_ext_sig_algorithm_hash OUTPUT Hash\n| where Hash != \"\"\n| eventstats count() AS count BY Hash\n| dedup Hash\n| sort - count\n| table Hash, count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_P62rnoPg": {
			"name": "Search_1 copy 3",
			"options": {
				"query": "| @spl2 FROM gigamon_dataset2\n| eval\n    ssl_common_name = json_extract(_raw, \"ssl_common_name\"),\n    app_name = json_extract(_raw, \"app_name\"),\n    ssl_validity_not_after = json_extract(_raw, \"ssl_validity_not_after\")\n| where ssl_validity_not_after != \"null\"\n    AND ssl_common_name != \"null\"\n    AND app_name != \"Unknown ssl\"\n    AND app_name != \"unknown\"\n| eval endtime = strptime(ssl_validity_not_after, \"%Y-%m-%d %H:%M:%S\")\n| eval Expiration_Time = strftime(endtime, \"%Y-%m-%d %H:%M:%S.%Q\")\n| eval curtime = now()\n| eval deltatime = endtime - curtime\n| eval Days_To_Expiration = round(deltatime / 86400)\n| table ssl_common_name, app_name, Days_To_Expiration, Expiration_Time\n| dedup ssl_common_name\n| where Days_To_Expiration < 0\n| stats count() AS expired_cert_count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_Q91kGdmW": {
			"name": "Search_1 copy 14",
			"options": {
				"query": "| @spl2\nFROM gigamon_dataset2\n| eval http_version = json_extract(_raw, \"http_version\")\n| where http_version IN (\"1.0\", \"1.1\", \"1.2\")\n| stats count() AS count BY http_version\n| rename http_version AS 'HTTP Version'\n| sort - count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_R0eoK0OG": {
			"name": "Search_1 copy 15",
			"options": {
				"query": "| @spl2\nFROM gigamon_dataset2\n| eval\n    src_ip = json_extract(_raw, \"src_ip\"),\n    dst_ip = json_extract(_raw, \"dst_ip\")\n| eval conversation = src_ip + \"->\" + dst_ip\n| stats count() AS ccount BY src_ip, dst_ip, conversation\n| sort - ccount\n| head 5\n| table src_ip, dst_ip, conversation, ccount",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_SN7BBsDj": {
			"name": "Search_1 copy 9",
			"options": {
				"query": "| @spl2\nFROM gigamon_dataset2\n| eval\n    app_name = json_extract(_raw, \"app_name\"),\n    dst_port = json_extract(_raw, \"dst_port\"),\n    src_port = json_extract(_raw, \"src_port\")\n| where app_name = \"ssh\"\n    AND dst_port != \"22\"\n    AND src_port != \"22\"\n| stats count() AS count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_Y1AR2jLh": {
			"name": "Search_1",
			"options": {
				"query": "| @spl2 FROM gigamon_dataset2\n| eval app_name = json_extract(_raw, \"app_name\")\n| where app_name IN (\"http\", \"https\", \"http2\")\n| stats count() AS count BY app_name\n| sort - count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_ZWwROuCO": {
			"name": "Search_1 copy 13",
			"options": {
				"query": "| @spl2\nFROM gigamon_dataset2\n| eval smb_version = json_extract(_raw, \"smb_version\")\n| stats count() AS ccount BY smb_version\n| rename smb_version AS 'SMB Version'\n| sort - ccount",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_otBvV8CX": {
			"name": "Search_1 copy 7",
			"options": {
				"query": "| @spl2\nFROM gigamon_dataset2\n| eval\n    src_ip = json_extract(_raw, \"src_ip\"),\n    dst_ip = json_extract(_raw, \"dst_ip\"),\n    app_name = json_extract(_raw, \"app_name\"),\n    ssl_protocol_version = json_extract(_raw, \"ssl_protocol_version\")\n| lookup SSL_version ssl_protocol_version OUTPUT Version\n| where Version IN (\"SSLv3\", \"SSLv2\", \"TLS1.0\")\n| table Version, src_ip, dst_ip, app_name",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		},
		"ds_wG3BMvMs": {
			"name": "Search_1 copy 4",
			"options": {
				"query": "| @spl2 FROM gigamon_dataset2\n| eval\n    ssl_validity_not_after_extracted = json_extract(_raw, \"ssl_validity_not_after\"),\n    ssl_common_name_extracted = json_extract(_raw, \"ssl_common_name\"),\n    app_name_extracted = json_extract(_raw, \"app_name\")\n| where ssl_validity_not_after_extracted != \"\"\n    AND ssl_common_name_extracted != \"\"\n    AND app_name_extracted != \"Unknown ssl\"\n    AND app_name_extracted != \"unknown\"\n| eval endtime = strptime(ssl_validity_not_after_extracted, \"%Y-%m-%d %H:%M:%S\")\n| eval Expiration_Time = strftime(endtime, \"%Y-%m-%d %H:%M:%S.%Q\")\n| eval curtime = now()\n| eval deltatime = endtime - curtime\n| eval Days_To_Expiration = round(deltatime / 86400)\n| table ssl_common_name_extracted, app_name_extracted, Days_To_Expiration, Expiration_Time\n| dedup ssl_common_name_extracted\n| where Days_To_Expiration < 0 AND Days_To_Expiration > 8\n| stats count() AS count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.spl2"
		}
	},
	"layout": {
